def main():
    """CLI for topology fingerprinting and search space generation."""
    parser = build_argument_parser()
    args = parser.parse_args()

    # Default -o to --dataset-dir when not provided
    if args.output is None:
        if args.dataset_dir:
            args.output = args.dataset_dir
        else:
            parser.error("-o/--output is required (unless --dataset-dir is provided)")

    # Validate --pattern-id dependencies and conflicts
    if args.pattern_id is not None:
        if not args.op_filter:
            parser.error("--pattern-id requires --op-filter")
        if args.shape_source:
            parser.error("--pattern-id and --shape-source are mutually exclusive")

    # Validate --shape-source / --pattern-source / --op-filter dependencies
    if args.shape_source and not args.pattern_source:
        parser.error("--shape-source requires --pattern-source")
    if args.pattern_source and not args.shape_source and args.pattern_id is None:
        parser.error("--pattern-source requires --shape-source or --pattern-id")
    if args.shape_source and not args.op_filter:
        parser.error("--shape-source requires --op-filter")
    if not args.shape_source and not args.dataset_dir and args.pattern_id is None and args.metadata is None:
        parser.error("metadata argument is required when not using --shape-source, --dataset-dir, or --pattern-id")

    # Validate --dataset-dir dependencies and conflicts
    if args.dataset_dir:
        if not args.op_filter:
            parser.error("--dataset-dir requires --op-filter")
        if args.augment:
            parser.error("--dataset-dir and --augment are mutually exclusive")
